/**
 * Сериализатор для создания заказа
 *
 * ⚙️ ПОЛНОСТЬЮ ЗАЩИЩЕННОЕ СОЗДАНИЕ ЗАКАЗА
 *
 * Используется операторами для создания заказа для клиента.
 *
 * 📌 АВТОМАТИЧЕСКИЕ ПОЛЯ (из ShiftSession оператора):
 * - business_point: автоматически определяется из активной смены оператора
 * - created_by: автоматически установится текущий оператор
 * - shift_session: привязывается к текущей смене оператора
 * - session: привязывается к дневной сессии из смены
 *
 * 📝 ТРЕБУЕМЫЕ ПОЛЯ:
 * - user: UID (UUID) клиента, для кого создается заказ (ОБЯЗАТЕЛЬНО)
 * - description: описание заказа (ОБЯЗАТЕЛЬНО)
 *
 * 🔓 ОПЦИОНАЛЬНЫЕ ПОЛЯ:
 * - template: шаблон заказа (ID)
 * - appeal: обращение, из которого создан заказ (ID, для преобразования обращения в заказ)
 * - amount: сумма заказа (default=0)
 * - is_paid: флаг оплаты (default=False)
 * - expected_ready_at: когда должен быть готов заказ
 *
 * ❌ business_point НЕ ПЕРЕДАВАЙТЕ в запросе! Определяется автоматически из ShiftSession оператора.
 *
 * 🛡️ ЗАЩИТА:
 * - Только операторы могут создать заказ
 * - Оператор должен иметь активную ShiftSession
 * - Заказ автоматически привязывается к текущей бизнес-точке оператора
 * - Невозможно создать заказ в другой бизнес-точке
 */
export type OrderCreateRequestWritable = {
    /**
     * UID (UUID) клиента. Используется, если appeal_id не передан.
     */
    user?: string;
    /**
     * Шаблон заказа
     *
     * ID шаблона заказа (опционально)
     */
    template?: number | null;
    /**
     * ID обращения. Если передан, клиент определяется автоматически из appeal_id.
     */
    appeal_id?: number;
    /**
     * Описание
     *
     * Описание заказа (ОБЯЗАТЕЛЬНО)
     */
    description: string;
    /**
     * Сумма
     *
     * Сумма заказа в рублях (default=0)
     */
    amount?: string;
    /**
     * Заказ оплачен
     *
     * Оплачен ли заказ (default=False)
     */
    is_paid?: boolean;
    /**
     * Ожидаемая дата готовности
     *
     * Когда должен быть готов заказ (опционально)
     */
    expected_ready_at?: string | null;
    /**
     * Оценка времени готовности в минутах. Если передана, expected_ready_at рассчитывается как now + estimated_time.
     */
    estimated_time?: number;
};

